VALUES
('bookkeeper-moex-01112', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列那種稅捐優先於一切債權及抵押權受償？', '["所得稅", "遺產稅", "貨物稅", "房屋稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01113', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法規定，財政部臺北國稅局應退納稅義務人之綜合所得稅，若該納稅義務人有下列之積欠， 何者應優先抵繳？', '["財政部臺北國稅局綜合所得稅之罰鍰", "財政部臺北國稅局贈與稅之欠稅", "財政部北區國稅局遺產稅之欠稅", "臺北市稅捐稽徵處地價稅之欠稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01114', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司有A、B兩筆房屋，其中A房屋有銀行貸款、積欠地價稅；B房屋欠繳房屋稅與地價稅，且該公 司尚積欠以前年度營利事業所得稅未繳。後因經營不善，導致A房屋被法院拍賣，若拍定價小於A房屋 銀行抵押債權，試問下列敘述何者正確？', '["A房屋的地價稅、拍賣產生的土地增值稅與營業稅、B房屋的地價稅、房屋稅須優先抵押債權受償", "A房屋的地價稅、拍賣產生的土地增值稅與營業稅、甲公司營利事業所得稅須優先抵押債權受償", "A房屋的地價稅、拍賣產生的土地增值稅、營業稅須優先抵押債權受償", "租稅課徵只優先普通債權，不得優先抵押債權，所以抵押債權最優先受償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01115', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關稅捐稽徵法之敘述何者錯誤？', '["財政部依本法或稅法所發布之解釋函令，對於據以申請之案件發生效力。但有利於納稅義務人者，對 於尚未核課確定之案件適用之", "財政部發布解釋函令，變更已發布解釋函令之法令見解，如不利於納稅義務人者，自發布日起或財政 部指定之將來一定期日起，發生效力", "財政部發布之稅務違章案件裁罰金額或倍數參考表變更時，有利於納稅義務人者，對於尚未核課確定 之案件適用之", "財政部發布解釋函令，變更已發布解釋函令之法令見解，如不利於納稅義務人者，於發布日或財政部 指定之將來一定期日前，應核課而未核課之稅捐及未確定案件才能適用該變更後之解釋函令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01116', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列有關退稅規定之敘述何者正確？', '["納稅義務人自行適用法令錯誤或計算錯誤溢繳之稅款，得自繳納之日起5年內提出具體證明，申請退還；屆 期未申請者，不得再行申請", "納稅義務人因稅捐稽徵機關適用法令錯誤、計算錯誤或其他可歸責於政府機關之錯誤，致溢繳稅款者，稅捐 稽徵機關應自知有錯誤原因之日起2年內查明退還，其退還之稅款以10年內溢繳者為限", "溢繳之稅款，納稅義務人以現金繳納者，應自其繳納該項稅款之日起，至填發收入退還書或國庫支票之日止， 按溢繳之稅額，依各年度1月1日郵政儲金一年期定期儲金固定利率，按日加計利息，一併退還", "納稅義務人應退之稅捐，稅捐稽徵機關不得再藉故扣抵納稅義務人其他積欠之稅捐，應立即退還納稅義務人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01117', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '個人出售於民國105年1月1日以後取得之房地產，有關綜合所得稅的課徵，下列何者錯誤？', '["課稅所得之計算，得減除當次交易依土地稅法規定計算之土地漲價總數額", "課稅所得之計算，得減除當次交易依土地稅法規定繳納之土地增值稅", "課稅所得不併計綜合所得總額", "不論有無應納稅額，應於完成所有權移轉登記之次日起30日內，填具申報書向稽徵機關辦理申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01118', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依相關稅法規定，於綜合所得稅計算課徵時，下列那項金額的變動不適用物價指數連動法？', '["免稅額", "標準扣除額", "教育學費特別扣除額", "身心障礙特別扣除額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01119', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依綜合所得稅計算課徵規定，下列那項僅限發生於納稅義務人之受扶養直系親屬時，才准許減除？', '["免稅額", "列舉扣除之捐贈", "列舉扣除之保險費", "列舉扣除之醫藥費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01120', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依相關稅法規定，中華民國境內居住之個人股東的可扣抵稅額如何計算？', '["股利淨額 × 稅額扣抵比率", "股利淨額 × 稅額扣抵比率 × 百分之十", "股利淨額 × 稅額扣抵比率 × 百分之二十", "股利淨額 × 稅額扣抵比率 × 百分之五十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01121', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依相關稅法規定，教育、文化、公益、慈善機關或團體，投資於國內其他營利事業，獲配 104 年之股利 淨額以及可扣抵稅額，於申報105年營利事業所得稅時如何處理？', '["股利淨額計入所得額，可扣抵稅額得扣抵應納稅額", "股利淨額不計入所得額，可扣抵稅額得扣抵應納稅額", "股利淨額計入所得額，可扣抵稅額不得扣抵應納稅額", "股利淨額不計入所得額，可扣抵稅額不得扣抵應納稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01122', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法及其相關法規規定，下列有關所得稅法居住者之定義何者正確？', '["陳董為中華民國國民，在我國境內設有戶籍。生活重心在境內，若陳董一年在臺停留合計未滿31天， 則非為我國境內居住者", "王先生有中華民國國籍，長年住在國外，生活重心在境外，但因某些因素在我國境內仍設有戶籍，若 王先生一年在臺停留合計滿31天，則視為我國境內居住者", "約翰屬於美國籍公民，雖因工作因素一年在臺居留合計滿183天，仍不會被視為我國居住者", "張先生為華僑，擁有雙重國籍，但長年居住在外，在我國並無戶籍，若張先生一年合計在臺停留超過 183天，則張先生在我國境內與大陸地區取得之所得應合併課徵綜合所得稅，辦理結算申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01123', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '林先生為中華民國境內居住者，民國103年12月20日登記買進A房地一筆、後於民國105年10月5日 賣出，試問下列有關申報該筆房地交易所得之敘述何者正確？', '["林先生於民國105年1月1日以前買入房地，不適用房地合一課稅制度", "林先生應計算售屋之財產交易所得，併計綜合所得總額課稅", "林先生應於房屋、土地完成所有權移轉登記日之次日起算30日內自行填具申報書，檢附契約書影本及 其他有關文件，向該管稽徵機關辦理申報繳納應納稅額", "若林先生賠錢出售該筆房地（虧損），因無應納稅額，所以無須向稽徵機關申報該筆房地交易"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01124', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關所得稅法規定房地合一課徵所得稅制度之敘述何者正確？', '["符合房地合一課稅要件之房地可以免徵土地增值稅", "房地合一課稅是依照出售時的房屋評定現值加土地公告現值為計算之基礎", "依農業發展條例申請興建之農舍不在房地合一課稅範圍", "計算房地合一課稅之交易所得時，依土地稅法規定繳納之土地增值稅，可以列為成本費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01125', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，下列敘述何者正確？', '["個人與證券商或銀行從事結構型商品交易之所得為利息所得", "個人取得短期票券到期兌償金額超過首次發售價格部分之利息所得採百分之十分離課稅", "依金融資產證券化條例或不動產證券化條例規定發行之受益證券或資產基礎證券分配之利息所得須併 入個人綜合所得總額計算", "個人持有公債、公司債及金融債券之利息所得可以適用所得稅法第17條儲蓄投資特別扣除額之規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01126', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，下列有關房地合一重購退稅之敘述何者錯誤？', '["個人出售自住房屋、土地依房地合一課稅制度繳納之稅額，自完成移轉登記之日或房屋使用權交易之 日起算2年內，重購自住房屋、土地者可以申請退還所納稅額", "得於重購自住房屋、土地完成移轉登記或房屋使用權交易之次日起算 5 年內，申請自前開出售時繳納 之稅額計算退還", "申請之條件必須為新購入之房地價格大於原出售之房地價格減除已納所得稅額", "重購退稅若為先購後售者亦適用之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01127', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，獨資合夥之營利事業應如何申報繳納所得稅？', '["只需計算營利事業所得額，不必繳納營利事業所得稅，直接課徵獨資資本主或合夥組織合夥人之綜合 所得稅", "需先繳納百分之十七的營利事業所得稅，稅後純益再由獨資資本主或合夥組織合夥人申報綜合所得稅", "需先計算其營利事業所得額與稅額，並以其全年應納稅額之半數，減除尚未抵繳之扣繳稅額，計算其 應納之結算稅額，於申報前自行繳納，小規模營利事業亦適用前述規定", "獨資合夥之營利事業所得額減除全年應納稅額半數後之餘額，應由獨資資本主或合夥組織合夥人依規 定列為營利所得，課徵綜合所得稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01128', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得基本稅額條例規定，營利事業基本所得額之計算，不屬於到期前指定平倉之期貨交易所得額，應 該採何種方法計算其交易成本？', '["先進先出法", "後進先出法", "個別辨認法", "加權平均法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01129', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依相關稅法規定，下列何者不是分期付款銷貨交易之當期損益計算方法？', '["普通銷貨法", "毛利百分比法", "全部毛利法", "賒銷百分比法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01130', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關營利事業或個人課徵所得基本稅額之敘述何者正確？', '["營利事業於102年度以後出售其持有滿3年以上屬所得稅法第4條之1規定之股票，於計算其當年度證券 交易所得時，減除其當年度出售該持有滿3年以上股票之交易損失，餘額為正者，以餘額半數計入當年度 證券交易所得，課徵所得基本稅額", "個人出售上市櫃股票之證券交易所得稅停徵，但出售未上市櫃股票之交易所得須計算繳納所得基本稅額", "營利事業出售上市櫃有價證券之證券交易所得稅停徵，也無須計入基本所得額中課稅", "營利事業之基本稅額，為依規定計算之基本所得額扣除新臺幣200萬元後，課徵稅率為百分之十二"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01131', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，下列有關營利事業稅捐費用之認列原則何者錯誤？', '["個人綜合所得稅及依加值型及非加值型營業稅法第51條、第52條規定追繳或繳納之營業稅，不得列 為營利事業之費用或損失", "對不動產課徵之稅捐費用認列（如房屋稅、地價稅及教育捐等），以本事業所有或向他人承租為限", "各種稅法所規定之滯納金、滯報金、怠報金等及各種法規所科處之罰鍰，暨未依法扣繳而補繳之稅款 不予認定", "營利事業出售土地所繳納之土地增值稅，應在該項出售土地之收入項下減除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01132', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '景美公司於民國105年1月1日新購小客車一輛供總經理公務使用，購入價新臺幣450萬元，耐用年數5年，估 計殘值50萬元，採用平均法提列折舊。依相關稅法規定，申報105年營利事業所得稅時，可提折舊金額多少元？', '["20萬元", "40萬元", "80萬元", "90萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01133', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '大安公司經營小客車租賃業務，於105年7月1日新購新臺幣600萬元小客車供出租使用，耐用年數4年，估計 殘值100萬元，採用平均法提列折舊。依相關稅法規定，申報105年營利事業所得稅時，可提折舊金額多少元？', '["50萬元", "62.5萬元", "100萬元", "125萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01134', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '自104年1月1日起，一般營利事業實際提供員工膳食，於申報營利事業所得稅時，每人每月最高可認 列的伙食費是新臺幣多少元？', '["1,500元", "2,400元", "3,000元", "3,600元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01135', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '若信義公司已成立職工福利委員會，依相關稅法規定，每月營業收入總額的多少百分比，於申報營利事 業所得稅時可被認列為職工福利金費用？', '["0.1%", "0.5%", "1%", "5%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01136', 'bookkeeper', 'bookkeeper-moex-105-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，營利事業銷售貨物或勞務，如有隨銷售附贈禮券、獎勵積點或保固服 務等，該附贈部分相對應之收入應如何計入課稅？', '["應於銷售時認列，不得遞延", "應列為遞延收入，待紅利積點兌換時才得列為收入", "應於營利事業所得稅結算申報書內營業收入調節欄項下調減", "應予遞延，待保固期限過後再列為收入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "04715853a329", "answer_pdf_sha1": "0ffd1a2d4104", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
